import { AfterViewInit, OnDestroy, ViewChild } from '@angular/core';
import { Subscription } from 'rxjs';
import {
  ListGridAfterRenderEvent,
  ListGridAfterRowRenderEvent,
  ListGridBeforeRowRenderEvent,
  ListGridComponent
} from 'wuic-framework-lib';

export class HostComponent implements AfterViewInit, OnDestroy {
  @ViewChild(ListGridComponent) grid?: ListGridComponent;
  private readonly subs = new Subscription();

  ngAfterViewInit(): void {
    if (!this.grid) return;

    this.subs.add(this.grid.onAfterRender.subscribe((e: ListGridAfterRenderEvent) => console.log(e)));
    this.subs.add(this.grid.onBeforeRowRender.subscribe((e: ListGridBeforeRowRenderEvent) => {
      // esempio cancel riga
      if (e.row?.deleted === true) e.cancelRender();
    }));
    this.subs.add(this.grid.onAfterRowRender.subscribe((e: ListGridAfterRowRenderEvent) => console.log(e)));
    this.subs.add(this.grid.onPaging.subscribe((e) => console.log('paging', e)));
    this.subs.add(this.grid.onSorting.subscribe((e) => console.log('sorting', e)));
    this.subs.add(this.grid.onFiltering.subscribe((e) => console.log('filtering', e)));
    this.subs.add(this.grid.onPTableSelectionChange.subscribe((e) => console.log('selection', e)));
    this.subs.add(this.grid.onPTableRowExpand.subscribe((e) => console.log('expand', e)));
    this.subs.add(this.grid.onPTableRowCollapse.subscribe((e) => console.log('collapse', e)));
    this.subs.add(this.grid.onPTableColumnResize.subscribe((e) => console.log('resize', e)));
    this.subs.add(this.grid.onPTableColumnReorder.subscribe((e) => console.log('reorder', e)));
  }

  ngOnDestroy(): void {
    this.subs.unsubscribe();
  }
}

