DECLARE @dbName NVARCHAR(256) = DB_NAME();
DECLARE @isBrokerEnabled BIT;

SELECT @isBrokerEnabled = is_broker_enabled
FROM sys.databases
WHERE name = @dbName;

IF @isBrokerEnabled = 1
BEGIN
    PRINT 'Service Broker already enabled for [' + @dbName + '].';
END
ELSE
BEGIN
    PRINT 'Enabling Service Broker for [' + @dbName + ']...';
    DECLARE @sql NVARCHAR(MAX);

    SET @sql = N'ALTER DATABASE [' + @dbName + N'] SET SINGLE_USER WITH ROLLBACK IMMEDIATE;';
    EXEC sp_executesql @sql;

    SET @sql = N'ALTER DATABASE [' + @dbName + N'] SET ENABLE_BROKER WITH NO_WAIT;';
    BEGIN TRY
        EXEC sp_executesql @sql;
    END TRY
    BEGIN CATCH
        -- Broker ID conflict (restored/attached DB): use NEW_BROKER
        SET @sql = N'ALTER DATABASE [' + @dbName + N'] SET NEW_BROKER WITH NO_WAIT;';
        EXEC sp_executesql @sql;
        PRINT 'Used NEW_BROKER (fresh broker identity).';
    END CATCH

    SET @sql = N'ALTER DATABASE [' + @dbName + N'] SET MULTI_USER;';
    EXEC sp_executesql @sql;

    SELECT @isBrokerEnabled = is_broker_enabled
    FROM sys.databases WHERE name = @dbName;

    IF @isBrokerEnabled = 1
        PRINT 'Service Broker enabled successfully.';
    ELSE
        PRINT 'WARNING: enable failed. Notifications will use polling.';
END

